import React, { useState } from 'react';
import { useNavigate, Link } from 'react-router-dom';
import { Mail, Lock, Loader2 } from 'lucide-react';
import { useAuth } from '../context/AuthContext'; 
import { api } from '../services/api'; 

const Login = () => {
  const [email, setEmail] = useState('');
  const [password, setPassword] = useState('');
  const [cargando, setCargando] = useState(false);
  
  const { login } = useAuth(); 
  const navigate = useNavigate();

  const handleLogin = async (e) => {
    e.preventDefault();
    setCargando(true);
    
    // Limpiamos mensajes previos en consola
    console.log("Iniciando proceso de login...");

    try {
      // 1. Llamada a la API
      const respuesta = await api.login(email, password);
      console.log("Respuesta completa del backend:", respuesta);

      // 2. Guardar sesión en Contexto/LocalStorage
      // Pasamos 'respuesta' porque contiene { token, user }
      login(respuesta); 

      // 3. Extraer el rol con seguridad del objeto 'user'
      const rolUsuario = respuesta.user?.rol; 
      console.log("Rol detectado:", rolUsuario);

      // 4. Lógica de direccionamiento
      if (rolUsuario === 'vendedor') {
        console.log("Redirigiendo a Dashboard de Vendedor");
        navigate('/dashboard');
      } else if (rolUsuario === 'cliente') {
        console.log("Redirigiendo a Panel de Cliente");
        navigate('/panel-cliente');
      } else {
        console.warn("Usuario logueado pero sin rol reconocido:", rolUsuario);
        alert("Tu cuenta no tiene un rol asignado correctamente.");
      }

    } catch (error) {
      console.error("Fallo en login:", error.message);
      alert(error.message);
    } finally {
      setCargando(false);
    }
  };

  return (
    <div style={containerStyle}>
      <form onSubmit={handleLogin} style={formStyle}>
        <div style={{ textAlign: 'center', marginBottom: '30px' }}>
          <h2 style={{ fontSize: '2rem', color: '#1e293b', margin: 0 }}>Bienvenido</h2>
          <p style={{ color: '#64748b' }}>Ingresa a tu cuenta de OfertasAPP</p>
        </div>
        
        <div style={inputGroup}>
          <label style={labelStyle}>Correo Electrónico</label>
          <div style={inputWrapper}>
            <Mail size={18} color="#94a3b8" />
            <input 
              type="email" 
              placeholder="correo@ejemplo.com" 
              style={inputStyle} 
              required 
              value={email}
              onChange={(e) => setEmail(e.target.value)}
            />
          </div>
        </div>

        <div style={inputGroup}>
          <label style={labelStyle}>Contraseña</label>
          <div style={inputWrapper}>
            <Lock size={18} color="#94a3b8" />
            <input 
              type="password" 
              placeholder="••••••••" 
              style={inputStyle} 
              required 
              value={password}
              onChange={(e) => setPassword(e.target.value)}
            />
          </div>
        </div>
        
        <button type="submit" style={btnSubmit} disabled={cargando}>
          {cargando ? (
            <div style={{ display: 'flex', alignItems: 'center', gap: '8px' }}>
              <Loader2 size={20} className="spinner" /> 
              Validando...
            </div>
          ) : "Iniciar Sesión"}
        </button>

        <p style={{ textAlign: 'center', marginTop: '20px', color: '#64748b' }}>
          ¿No tienes cuenta? <Link to="/registro" style={linkStyle}>Regístrate aquí</Link>
        </p>
      </form>

      <style>{`
        .spinner { animation: spin 1s linear infinite; }
        @keyframes spin { from { transform: rotate(0deg); } to { transform: rotate(360deg); } }
      `}</style>
    </div>
  );
};

// --- Estilos ---
const linkStyle = { color: '#e67e22', fontWeight: 'bold', textDecoration: 'none' };
const containerStyle = { display: 'flex', justifyContent: 'center', alignItems: 'center', minHeight: '85vh', background: '#f8fafc' };
const formStyle = { background: 'white', padding: '40px', borderRadius: '24px', boxShadow: '0 20px 25px -5px rgba(0,0,0,0.1)', width: '100%', maxWidth: '400px' };
const inputGroup = { marginBottom: '20px' };
const labelStyle = { display: 'block', marginBottom: '8px', fontSize: '0.9rem', fontWeight: '600', color: '#475569' };
const inputWrapper = { display: 'flex', alignItems: 'center', gap: '10px', background: '#f1f5f9', padding: '0 15px', borderRadius: '12px', border: '1px solid #e2e8f0' };
const inputStyle = { width: '100%', padding: '12px 0', border: 'none', background: 'transparent', outline: 'none', fontSize: '1rem' };
const btnSubmit = { width: '100%', padding: '14px', background: '#1e293b', color: 'white', border: 'none', borderRadius: '12px', fontWeight: 'bold', cursor: 'pointer', fontSize: '1rem', marginTop: '10px', display: 'flex', justifyContent: 'center' };

export default Login;
